// ParseOccurrence decodes one occurrence record (header included).
// keys is nil when id is a widget id; otherwise id is a template
// node id and keys is the copy's key path, outermost first. payload
// is the entry's new text (string) for occTextChanged, the
// checkbox's new state (bool) for occToggled, the slider's new
// value (float64) for occValueChanged, nil for clicks. ok is
// false for pad/unknown records.
func ParseOccurrence(rec []byte) (kind uint16, id uint64, keys []any, payload any, ok bool) {
	kind = binary.LittleEndian.Uint16(rec[4:])
	if kind != occButtonClicked && kind != occTextChanged && kind != occToggled && kind != occValueChanged && kind != occCloseRequested && kind != occWindowClosed && kind != occAlertResult && kind != occEntryPopped && kind != occBackRequested && kind != occSectionSelected {
		return 0, 0, nil, nil, false
	}
	id = binary.LittleEndian.Uint64(rec[8:])
	if kind == occAlertResult {
		// The alert's one answer: id + u32 choice (AlertChoice*).
		return kind, id, nil, binary.LittleEndian.Uint32(rec[16:]), true
	}
	if kind == occCloseRequested || kind == occWindowClosed || kind == occEntryPopped || kind == occBackRequested {
		// Surface lifecycle records carry the surface id alone —
		// no key path, no payload (derived from the record shapes).
		return kind, id, nil, nil, true
	}
	if kind == occSectionSelected {
		// Surface-pair records (window, section): the SECOND id
		// keys the handler; the first rides as the payload.
		return kind, binary.LittleEndian.Uint64(rec[16:]), nil, id, true
	}
	pathLen := binary.LittleEndian.Uint32(rec[16:])
	at := 24
	for i := uint32(0); i < pathLen; i++ {
		vtype := binary.LittleEndian.Uint32(rec[at:])
		vlen := int(binary.LittleEndian.Uint32(rec[at+4:]))
		payload := rec[at+8 : at+8+vlen]
		switch vtype {
		case ValueBool:
			keys = append(keys, payload[0] != 0)
		case ValueI64:
			keys = append(keys, int64(binary.LittleEndian.Uint64(payload)))
		case ValueF64:
			keys = append(keys, math.Float64frombits(binary.LittleEndian.Uint64(payload)))
		default:
			keys = append(keys, string(payload))
		}
		at += 8 + (vlen+7)&^7
	}
	if kind == occTextChanged || kind == occToggled || kind == occValueChanged {
		vtype := binary.LittleEndian.Uint32(rec[at:])
		vlen := int(binary.LittleEndian.Uint32(rec[at+4:]))
		switch vtype {
		case ValueBool:
			payload = rec[at+8] != 0
		case ValueI64:
			payload = int64(binary.LittleEndian.Uint64(rec[at+8:]))
		case ValueF64:
			payload = math.Float64frombits(binary.LittleEndian.Uint64(rec[at+8:]))
		default:
			payload = string(rec[at+8 : at+8+vlen])
		}
	}
	return kind, id, keys, payload, true
}
